import{_ as o,o as r,c as n,a2 as s}from"./chunks/framework.DnrXFDHb.js";const c=JSON.parse('{"title":"功法大全","description":"","frontmatter":{},"headers":[],"relativePath":"guide/gongfa.md","filePath":"guide/gongfa.md","lastUpdated":null}'),g={name:"guide/gongfa.md"};function l(a,t,i,e,d,h){return r(),n("div",null,[...t[0]||(t[0]=[s('<h1 id="功法大全" tabindex="-1">功法大全 <a class="header-anchor" href="#功法大全" aria-label="Permalink to &quot;功法大全&quot;">​</a></h1><p>修仙功法共 <strong>28种</strong>，分为攻击、防御、辅助、身法四大类型，从练气到飞升层层解锁。</p><h2 id="通用机制" tabindex="-1">通用机制 <a class="header-anchor" href="#通用机制" aria-label="Permalink to &quot;通用机制&quot;">​</a></h2><table tabindex="0"><thead><tr><th>参数</th><th>值</th><th>说明</th></tr></thead><tbody><tr><td>全局冷却</td><td>5秒</td><td>释放任意功法后所有功法进入冷却</td></tr><tr><td>灵气消耗基数</td><td>12.0</td><td>功法底层计算参数</td></tr></tbody></table><hr><h2 id="练气期功法" tabindex="-1">练气期功法 <a class="header-anchor" href="#练气期功法" aria-label="Permalink to &quot;练气期功法&quot;">​</a></h2><h3 id="灵气弹-1" tabindex="-1">灵气弹（#1） <a class="header-anchor" href="#灵气弹-1" aria-label="Permalink to &quot;灵气弹（#1）&quot;">​</a></h3><ul><li><strong>类型</strong>：🔴攻击 | <strong>灵根</strong>：🔥火 | <strong>所需</strong>：练气1阶</li><li><strong>灵气消耗</strong>：20 | <strong>冷却</strong>：8秒 | <strong>威力倍率</strong>：×1.0</li><li><strong>弹幕ID</strong>：16 | <strong>弹幕速度</strong>：12.0 | <strong>击退</strong>：5.0 | <strong>基础伤害</strong>：50</li><li><strong>传送距离</strong>：20格</li><li><blockquote><p>凝聚灵气发出冲击弹，造成灵气伤害</p></blockquote></li></ul><h3 id="灵刃斩-2" tabindex="-1">灵刃斩（#2） <a class="header-anchor" href="#灵刃斩-2" aria-label="Permalink to &quot;灵刃斩（#2）&quot;">​</a></h3><ul><li><strong>类型</strong>：🔴攻击 | <strong>灵根</strong>：🔶金 | <strong>所需</strong>：练气2阶</li><li><strong>灵气消耗</strong>：25 | <strong>冷却</strong>：10秒 | <strong>威力倍率</strong>：×1.1</li><li><strong>弹幕ID</strong>：3 | <strong>弹幕速度</strong>：14.0 | <strong>击退</strong>：6.0 | <strong>基础伤害</strong>：55</li><li><strong>传送距离</strong>：20格</li><li><blockquote><p>化气为刃，向前斩出锋利灵气波</p></blockquote></li></ul><h3 id="护体罡气-3" tabindex="-1">护体罡气（#3） <a class="header-anchor" href="#护体罡气-3" aria-label="Permalink to &quot;护体罡气（#3）&quot;">​</a></h3><ul><li><strong>类型</strong>：🛡️防御 | <strong>灵根</strong>：🪨土 | <strong>所需</strong>：练气3阶</li><li><strong>灵气消耗</strong>：30 | <strong>冷却</strong>：30秒 | <strong>威力倍率</strong>：×1.0</li><li><strong>BuffID</strong>：36 | <strong>持续</strong>：10秒 | <strong>额外防御</strong>：+15 | <strong>额外速度</strong>：×1.0 | <strong>生命恢复</strong>：+0</li><li><blockquote><p>凝聚灵气护体，10秒内防御+15 + 寒冰护盾Buff</p></blockquote></li></ul><h3 id="水镜盾-4" tabindex="-1">水镜盾（#4） <a class="header-anchor" href="#水镜盾-4" aria-label="Permalink to &quot;水镜盾（#4）&quot;">​</a></h3><ul><li><strong>类型</strong>：🛡️防御 | <strong>灵根</strong>：💧水 | <strong>所需</strong>：练气4阶</li><li><strong>灵气消耗</strong>：25 | <strong>冷却</strong>：25秒 | <strong>威力倍率</strong>：×1.0</li><li><strong>BuffID</strong>：15 | <strong>持续</strong>：8秒 | <strong>额外防御</strong>：+10 | <strong>额外速度</strong>：×1.0 | <strong>生命恢复</strong>：+0</li><li><blockquote><p>凝聚水灵之力形成护盾，8秒内吸收伤害</p></blockquote></li></ul><h3 id="缠绕术-5" tabindex="-1">缠绕术（#5） <a class="header-anchor" href="#缠绕术-5" aria-label="Permalink to &quot;缠绕术（#5）&quot;">​</a></h3><ul><li><strong>类型</strong>：💚辅助 | <strong>灵根</strong>：🌿木 | <strong>所需</strong>：练气5阶</li><li><strong>灵气消耗</strong>：20 | <strong>冷却</strong>：20秒 | <strong>威力倍率</strong>：×1.0</li><li><strong>BuffID</strong>：20 | <strong>持续</strong>：6秒 | <strong>额外防御</strong>：+0 | <strong>额外速度</strong>：×0.6（减速） | <strong>生命恢复</strong>：-2（伤害）</li><li><blockquote><p>召唤藤蔓缠绕敌人，6秒内减速并持续造成小额伤害</p></blockquote></li></ul><hr><h2 id="筑基期功法" tabindex="-1">筑基期功法 <a class="header-anchor" href="#筑基期功法" aria-label="Permalink to &quot;筑基期功法&quot;">​</a></h2><h3 id="御剑术-6" tabindex="-1">御剑术（#6） <a class="header-anchor" href="#御剑术-6" aria-label="Permalink to &quot;御剑术（#6）&quot;">​</a></h3><ul><li><strong>类型</strong>：🔴攻击 | <strong>灵根</strong>：🔶金 | <strong>所需</strong>：筑基1阶</li><li><strong>灵气消耗</strong>：40 | <strong>冷却</strong>：10秒 | <strong>威力倍率</strong>：×1.5</li><li><strong>弹幕ID</strong>：6 | <strong>弹幕速度</strong>：12.0 | <strong>击退</strong>：5.0 | <strong>基础伤害</strong>：50</li><li><strong>传送距离</strong>：20格</li><li><blockquote><p>御剑飞行攻击，对目标造成高额伤害</p></blockquote></li></ul><h3 id="回春术-10" tabindex="-1">回春术（#10） <a class="header-anchor" href="#回春术-10" aria-label="Permalink to &quot;回春术（#10）&quot;">​</a></h3><ul><li><strong>类型</strong>：💚辅助 | <strong>灵根</strong>：🌿木 | <strong>所需</strong>：筑基2阶</li><li><strong>灵气消耗</strong>：35 | <strong>冷却</strong>：35秒 | <strong>威力倍率</strong>：×1.0</li><li><strong>BuffID</strong>：25 | <strong>持续</strong>：10秒 | <strong>额外防御</strong>：+0 | <strong>额外速度</strong>：×1.0 | <strong>生命恢复</strong>：<strong>+5/秒</strong></li><li><blockquote><p>运用木灵之力，10秒内持续回血（共恢复50HP）</p></blockquote></li></ul><h3 id="缩地成寸-7" tabindex="-1">缩地成寸（#7） <a class="header-anchor" href="#缩地成寸-7" aria-label="Permalink to &quot;缩地成寸（#7）&quot;">​</a></h3><ul><li><strong>类型</strong>：🏃身法 | <strong>灵根</strong>：💧水 | <strong>所需</strong>：筑基3阶</li><li><strong>灵气消耗</strong>：25 | <strong>冷却</strong>：15秒 | <strong>威力倍率</strong>：×1.0</li><li><strong>传送距离</strong>：<strong>20格</strong>（非弹幕，直接瞬移）</li><li><blockquote><p>短距离空间传送，向前瞬移20格</p></blockquote></li></ul><h3 id="火蛇术-8" tabindex="-1">火蛇术（#8） <a class="header-anchor" href="#火蛇术-8" aria-label="Permalink to &quot;火蛇术（#8）&quot;">​</a></h3><ul><li><strong>类型</strong>：🔴攻击 | <strong>灵根</strong>：🔥火 | <strong>所需</strong>：筑基5阶</li><li><strong>灵气消耗</strong>：45 | <strong>冷却</strong>：12秒 | <strong>威力倍率</strong>：×1.6</li><li><strong>弹幕ID</strong>：15 | <strong>弹幕速度</strong>：10.0 | <strong>击退</strong>：4.0 | <strong>基础伤害</strong>：60</li><li><strong>传送距离</strong>：20格</li><li><blockquote><p>释放火焰灵蛇追踪敌人，造成持续性火焰伤害</p></blockquote></li></ul><h3 id="岩铠术-9" tabindex="-1">岩铠术（#9） <a class="header-anchor" href="#岩铠术-9" aria-label="Permalink to &quot;岩铠术（#9）&quot;">​</a></h3><ul><li><strong>类型</strong>：🛡️防御 | <strong>灵根</strong>：🪨土 | <strong>所需</strong>：筑基7阶</li><li><strong>灵气消耗</strong>：50 | <strong>冷却</strong>：50秒 | <strong>威力倍率</strong>：×1.0</li><li><strong>BuffID</strong>：114 | <strong>持续</strong>：12秒 | <strong>额外防御</strong>：+25 | <strong>额外速度</strong>：×1.0 | <strong>生命恢复</strong>：+0</li><li><blockquote><p>召唤岩之铠甲，12秒内防御+25</p></blockquote></li></ul><hr><h2 id="金丹期功法" tabindex="-1">金丹期功法 <a class="header-anchor" href="#金丹期功法" aria-label="Permalink to &quot;金丹期功法&quot;">​</a></h2><h3 id="丹火焚天-11" tabindex="-1">丹火焚天（#11） <a class="header-anchor" href="#丹火焚天-11" aria-label="Permalink to &quot;丹火焚天（#11）&quot;">​</a></h3><ul><li><strong>类型</strong>：🔴攻击 | <strong>灵根</strong>：🔥火 | <strong>所需</strong>：金丹1阶</li><li><strong>灵气消耗</strong>：60 | <strong>冷却</strong>：12秒 | <strong>威力倍率</strong>：×2.0</li><li><strong>弹幕ID</strong>：34 | <strong>弹幕速度</strong>：12.0 | <strong>击退</strong>：5.0 | <strong>基础伤害</strong>：50</li><li><strong>传送距离</strong>：20格</li><li><blockquote><p>释放金丹真火，焚烧大范围敌人</p></blockquote></li></ul><h3 id="生生不息-12" tabindex="-1">生生不息（#12） <a class="header-anchor" href="#生生不息-12" aria-label="Permalink to &quot;生生不息（#12）&quot;">​</a></h3><ul><li><strong>类型</strong>：💚辅助 | <strong>灵根</strong>：🌿木 | <strong>所需</strong>：金丹2阶</li><li><strong>灵气消耗</strong>：50 | <strong>冷却</strong>：60秒 | <strong>威力倍率</strong>：×1.0</li><li><strong>BuffID</strong>：25 | <strong>持续</strong>：15秒 | <strong>额外防御</strong>：+0 | <strong>额外速度</strong>：×1.0 | <strong>生命恢复</strong>：<strong>+8/秒</strong></li><li><blockquote><p>运用木灵之力，15秒内持续大幅回血（共恢复120HP）+ 再生Buff</p></blockquote></li></ul><h3 id="金钟罩-13" tabindex="-1">金钟罩（#13） <a class="header-anchor" href="#金钟罩-13" aria-label="Permalink to &quot;金钟罩（#13）&quot;">​</a></h3><ul><li><strong>类型</strong>：🛡️防御 | <strong>灵根</strong>：🔶金 | <strong>所需</strong>：金丹3阶</li><li><strong>灵气消耗</strong>：70 | <strong>冷却</strong>：45秒 | <strong>威力倍率</strong>：×1.0</li><li><strong>BuffID</strong>：114 | <strong>持续</strong>：12秒 | <strong>额外防御</strong>：+30 | <strong>额外速度</strong>：×1.0 | <strong>生命恢复</strong>：+0</li><li><blockquote><p>金刚不坏，12秒内+30防 + 圣骑士护盾Buff</p></blockquote></li></ul><h3 id="冰封术-14" tabindex="-1">冰封术（#14） <a class="header-anchor" href="#冰封术-14" aria-label="Permalink to &quot;冰封术（#14）&quot;">​</a></h3><ul><li><strong>类型</strong>：🔴攻击 | <strong>灵根</strong>：💧水 | <strong>所需</strong>：金丹4阶</li><li><strong>灵气消耗</strong>：65 | <strong>冷却</strong>：16秒 | <strong>威力倍率</strong>：×1.8</li><li><strong>弹幕ID</strong>：475 | <strong>弹幕速度</strong>：10.0 | <strong>击退</strong>：3.0 | <strong>基础伤害</strong>：70</li><li><strong>传送距离</strong>：20格</li><li><blockquote><p>凝聚冰寒之力冻结目标，造成伤害并减速</p></blockquote></li></ul><h3 id="山岳镇压-15" tabindex="-1">山岳镇压（#15） <a class="header-anchor" href="#山岳镇压-15" aria-label="Permalink to &quot;山岳镇压（#15）&quot;">​</a></h3><ul><li><strong>类型</strong>：🔴攻击 | <strong>灵根</strong>：🪨土 | <strong>所需</strong>：金丹5阶</li><li><strong>灵气消耗</strong>：80 | <strong>冷却</strong>：20秒 | <strong>威力倍率</strong>：×2.2</li><li><strong>弹幕ID</strong>：37 | <strong>弹幕速度</strong>：8.0 | <strong>击退</strong>：8.0 | <strong>基础伤害</strong>：80</li><li><strong>传送距离</strong>：20格</li><li><blockquote><p>召唤山岳之力镇压敌人，大范围伤害+强击退</p></blockquote></li></ul><h3 id="金丹化神-16" tabindex="-1">金丹化神（#16） <a class="header-anchor" href="#金丹化神-16" aria-label="Permalink to &quot;金丹化神（#16）&quot;">​</a></h3><ul><li><strong>类型</strong>：💚辅助 | <strong>灵根</strong>：🌟天 | <strong>所需</strong>：金丹7阶</li><li><strong>灵气消耗</strong>：100 | <strong>冷却</strong>：180秒（3分钟） | <strong>威力倍率</strong>：×1.0</li><li><strong>BuffID</strong>：152 | <strong>持续</strong>：15秒 | <strong>额外防御</strong>：+20 | <strong>额外速度</strong>：×1.2 | <strong>生命恢复</strong>：+3/秒</li><li><blockquote><p>短暂进入神化状态，15秒内全属性提升20%</p></blockquote></li></ul><hr><h2 id="元婴期功法" tabindex="-1">元婴期功法 <a class="header-anchor" href="#元婴期功法" aria-label="Permalink to &quot;元婴期功法&quot;">​</a></h2><h3 id="元婴出窍-17" tabindex="-1">元婴出窍（#17） <a class="header-anchor" href="#元婴出窍-17" aria-label="Permalink to &quot;元婴出窍（#17）&quot;">​</a></h3><ul><li><strong>类型</strong>：💚辅助 | <strong>灵根</strong>：🌟天 | <strong>所需</strong>：元婴1阶</li><li><strong>灵气消耗</strong>：80 | <strong>冷却</strong>：120秒（2分钟） | <strong>威力倍率</strong>：×1.0</li><li><strong>BuffID</strong>：117 | <strong>持续</strong>：20秒 | <strong>额外防御</strong>：+0 | <strong>额外速度</strong>：×1.0 | <strong>生命恢复</strong>：+0</li><li><blockquote><p>元婴离体，进入<strong>隐身状态20秒</strong></p></blockquote></li></ul><h3 id="天雷引-18" tabindex="-1">天雷引（#18） <a class="header-anchor" href="#天雷引-18" aria-label="Permalink to &quot;天雷引（#18）&quot;">​</a></h3><ul><li><strong>类型</strong>：🔴攻击 | <strong>灵根</strong>：🔶金 | <strong>所需</strong>：元婴3阶</li><li><strong>灵气消耗</strong>：90 | <strong>冷却</strong>：18秒 | <strong>威力倍率</strong>：×2.5</li><li><strong>弹幕ID</strong>：580 | <strong>弹幕速度</strong>：12.0 | <strong>击退</strong>：5.0 | <strong>基础伤害</strong>：50</li><li><strong>传送距离</strong>：20格</li><li><blockquote><p>引动天雷降世，对目标造成毁灭性伤害</p></blockquote></li></ul><h3 id="焚天劫火-19" tabindex="-1">焚天劫火（#19） <a class="header-anchor" href="#焚天劫火-19" aria-label="Permalink to &quot;焚天劫火（#19）&quot;">​</a></h3><ul><li><strong>类型</strong>：🔴攻击 | <strong>灵根</strong>：🔥火 | <strong>所需</strong>：元婴5阶</li><li><strong>灵气消耗</strong>：120 | <strong>冷却</strong>：22秒 | <strong>威力倍率</strong>：×2.8</li><li><strong>弹幕ID</strong>：95 | <strong>弹幕速度</strong>：11.0 | <strong>击退</strong>：4.0 | <strong>基础伤害</strong>：90</li><li><strong>传送距离</strong>：20格</li><li><blockquote><p>释放焚天劫火，对大范围目标造成毁灭性燃烧伤害</p></blockquote></li></ul><h3 id="万象森罗-20" tabindex="-1">万象森罗（#20） <a class="header-anchor" href="#万象森罗-20" aria-label="Permalink to &quot;万象森罗（#20）&quot;">​</a></h3><ul><li><strong>类型</strong>：💚辅助 | <strong>灵根</strong>：🌿木 | <strong>所需</strong>：元婴7阶</li><li><strong>灵气消耗</strong>：100 | <strong>冷却</strong>：90秒 | <strong>威力倍率</strong>：×1.0</li><li><strong>BuffID</strong>：25 | <strong>持续</strong>：15秒 | <strong>额外防御</strong>：+10 | <strong>额外速度</strong>：×1.0 | <strong>生命恢复</strong>：<strong>+10/秒</strong></li><li><blockquote><p>展开森罗结界，15秒内队友持续回血（共恢复150HP）</p></blockquote></li></ul><hr><h2 id="化神期功法" tabindex="-1">化神期功法 <a class="header-anchor" href="#化神期功法" aria-label="Permalink to &quot;化神期功法&quot;">​</a></h2><h3 id="化神领域-21" tabindex="-1">化神领域（#21） <a class="header-anchor" href="#化神领域-21" aria-label="Permalink to &quot;化神领域（#21）&quot;">​</a></h3><ul><li><strong>类型</strong>：💚辅助 | <strong>灵根</strong>：🌟天 | <strong>所需</strong>：化神1阶</li><li><strong>灵气消耗</strong>：120 | <strong>冷却</strong>：180秒（3分钟） | <strong>威力倍率</strong>：×1.0</li><li><strong>BuffID</strong>：152 | <strong>持续</strong>：25秒 | <strong>额外防御</strong>：+25 | <strong>额外速度</strong>：×1.25 | <strong>生命恢复</strong>：+5/秒</li><li><blockquote><p>展开化神领域，25秒内全属性大幅提升 + 灵气光环Buff</p></blockquote></li></ul><h3 id="万剑归宗-22" tabindex="-1">万剑归宗（#22） <a class="header-anchor" href="#万剑归宗-22" aria-label="Permalink to &quot;万剑归宗（#22）&quot;">​</a></h3><ul><li><strong>类型</strong>：🔴攻击 | <strong>灵根</strong>：🔶金 | <strong>所需</strong>：化神3阶</li><li><strong>灵气消耗</strong>：150 | <strong>冷却</strong>：25秒 | <strong>威力倍率</strong>：×3.0</li><li><strong>弹幕ID</strong>：7 | <strong>弹幕速度</strong>：14.0 | <strong>击退</strong>：6.0 | <strong>基础伤害</strong>：100</li><li><strong>传送距离</strong>：20格</li><li><blockquote><p>凝聚万剑之力，全屏范围剑雨打击</p></blockquote></li></ul><h3 id="沧海横流-23" tabindex="-1">沧海横流（#23） <a class="header-anchor" href="#沧海横流-23" aria-label="Permalink to &quot;沧海横流（#23）&quot;">​</a></h3><ul><li><strong>类型</strong>：🔴攻击 | <strong>灵根</strong>：💧水 | <strong>所需</strong>：化神5阶</li><li><strong>灵气消耗</strong>：140 | <strong>冷却</strong>：20秒 | <strong>威力倍率</strong>：×2.8</li><li><strong>弹幕ID</strong>：262 | <strong>弹幕速度</strong>：9.0 | <strong>击退</strong>：7.0 | <strong>基础伤害</strong>：95</li><li><strong>传送距离</strong>：20格</li><li><blockquote><p>引动沧海之力，召唤巨浪冲击全场</p></blockquote></li></ul><h3 id="不动明王-24" tabindex="-1">不动明王（#24） <a class="header-anchor" href="#不动明王-24" aria-label="Permalink to &quot;不动明王（#24）&quot;">​</a></h3><ul><li><strong>类型</strong>：🛡️防御 | <strong>灵根</strong>：🪨土 | <strong>所需</strong>：化神7阶</li><li><strong>灵气消耗</strong>：160 | <strong>冷却</strong>：90秒 | <strong>威力倍率</strong>：×1.0</li><li><strong>BuffID</strong>：114 | <strong>持续</strong>：20秒 | <strong>额外防御</strong>：+40 | <strong>额外速度</strong>：×1.0 | <strong>免疫击退</strong> | <strong>生命恢复</strong>：+0</li><li><blockquote><p>化身不动明王，20秒内防御+40，免疫击退</p></blockquote></li></ul><hr><h2 id="渡劫期功法" tabindex="-1">渡劫期功法 <a class="header-anchor" href="#渡劫期功法" aria-label="Permalink to &quot;渡劫期功法&quot;">​</a></h2><h3 id="万雷归一-25" tabindex="-1">万雷归一（#25） <a class="header-anchor" href="#万雷归一-25" aria-label="Permalink to &quot;万雷归一（#25）&quot;">​</a></h3><ul><li><strong>类型</strong>：🔴攻击 | <strong>灵根</strong>：🔥火 | <strong>所需</strong>：渡劫1阶</li><li><strong>灵气消耗</strong>：150 | <strong>冷却</strong>：25秒 | <strong>威力倍率</strong>：×3.0</li><li><strong>弹幕ID</strong>：633 | <strong>弹幕速度</strong>：12.0 | <strong>击退</strong>：5.0 | <strong>基础伤害</strong>：50</li><li><strong>传送距离</strong>：20格</li><li><blockquote><p>引万雷归一，对全屏敌人造成毁灭打击</p></blockquote></li></ul><h3 id="天劫护体-26" tabindex="-1">天劫护体（#26） <a class="header-anchor" href="#天劫护体-26" aria-label="Permalink to &quot;天劫护体（#26）&quot;">​</a></h3><ul><li><strong>类型</strong>：🛡️防御 | <strong>灵根</strong>：🪨土 | <strong>所需</strong>：渡劫5阶</li><li><strong>灵气消耗</strong>：200 | <strong>冷却</strong>：120秒（2分钟） | <strong>威力倍率</strong>：×1.0</li><li><strong>BuffID</strong>：36 | <strong>持续</strong>：15秒 | <strong>额外防御</strong>：+60 | <strong>额外速度</strong>：×1.0 | <strong>生命恢复</strong>：+3/秒</li><li><blockquote><p>引天劫之力护体，15秒内防御+60，<strong>反弹50%伤害</strong></p></blockquote></li></ul><hr><h2 id="大乘期功法" tabindex="-1">大乘期功法 <a class="header-anchor" href="#大乘期功法" aria-label="Permalink to &quot;大乘期功法&quot;">​</a></h2><h3 id="大罗天斩-27" tabindex="-1">大罗天斩（#27） <a class="header-anchor" href="#大罗天斩-27" aria-label="Permalink to &quot;大罗天斩（#27）&quot;">​</a></h3><ul><li><strong>类型</strong>：🔴攻击 | <strong>灵根</strong>：🔶金 | <strong>所需</strong>：大乘1阶</li><li><strong>灵气消耗</strong>：280 | <strong>冷却</strong>：30秒 | <strong>威力倍率</strong>：×4.5</li><li><strong>弹幕ID</strong>：8 | <strong>弹幕速度</strong>：18.0 | <strong>击退</strong>：10.0 | <strong>基础伤害</strong>：200</li><li><strong>传送距离</strong>：20格</li><li><blockquote><p>大乘期修士的至强一击，斩裂虚空粉碎万物</p></blockquote></li></ul><hr><h2 id="飞升期功法" tabindex="-1">飞升期功法 <a class="header-anchor" href="#飞升期功法" aria-label="Permalink to &quot;飞升期功法&quot;">​</a></h2><h3 id="飞升羽化-28-⭐终极功法" tabindex="-1">飞升羽化（#28）⭐终极功法 <a class="header-anchor" href="#飞升羽化-28-⭐终极功法" aria-label="Permalink to &quot;飞升羽化（#28）⭐终极功法&quot;">​</a></h3><ul><li><strong>类型</strong>：💚辅助 | <strong>灵根</strong>：🌟天 | <strong>所需</strong>：飞升1阶</li><li><strong>灵气消耗</strong>：500 | <strong>冷却</strong>：300秒（5分钟） | <strong>威力倍率</strong>：×1.0</li><li><strong>BuffID</strong>：152 | <strong>持续</strong>：30秒 | <strong>额外防御</strong>：+100 | <strong>额外速度</strong>：×1.5 | <strong>生命恢复</strong>：+20/秒</li><li><blockquote><p>引天地大道之力，30秒内全属性翻倍，<strong>免疫一切伤害</strong></p></blockquote></li></ul><hr><h2 id="功法类型统计" tabindex="-1">功法类型统计 <a class="header-anchor" href="#功法类型统计" aria-label="Permalink to &quot;功法类型统计&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类型</th><th>数量</th><th>功法列表</th></tr></thead><tbody><tr><td>🔴 攻击</td><td>14</td><td>灵气弹、灵刃斩、御剑术、火蛇术、丹火焚天、冰封术、山岳镇压、天雷引、焚天劫火、万剑归宗、沧海横流、万雷归一、大罗天斩</td></tr><tr><td>🛡️ 防御</td><td>6</td><td>护体罡气、水镜盾、岩铠术、金钟罩、不动明王、天劫护体</td></tr><tr><td>💚 辅助</td><td>7</td><td>缠绕术、回春术、生生不息、金丹化神、元婴出窍、万象森罗、化神领域、飞升羽化</td></tr><tr><td>🏃 身法</td><td>1</td><td>缩地成寸</td></tr></tbody></table><hr><h2 id="灵根功法对应表" tabindex="-1">灵根功法对应表 <a class="header-anchor" href="#灵根功法对应表" aria-label="Permalink to &quot;灵根功法对应表&quot;">​</a></h2><table tabindex="0"><thead><tr><th>灵根</th><th>攻击</th><th>防御</th><th>辅助/身法</th><th>合计</th></tr></thead><tbody><tr><td>🔶 金</td><td>灵刃斩、御剑术、天雷引、万剑归宗、大罗天斩</td><td>金钟罩</td><td>—</td><td>6</td></tr><tr><td>🌿 木</td><td>—</td><td>—</td><td>缠绕术、回春术、生生不息、万象森罗</td><td>4</td></tr><tr><td>💧 水</td><td>冰封术、沧海横流</td><td>水镜盾</td><td>缩地成寸(身法)</td><td>4</td></tr><tr><td>🔥 火</td><td>灵气弹、火蛇术、丹火焚天、焚天劫火、万雷归一</td><td>—</td><td>—</td><td>5</td></tr><tr><td>🪨 土</td><td>山岳镇压</td><td>护体罡气、岩铠术、不动明王、天劫护体</td><td>—</td><td>5</td></tr><tr><td>🌟 天</td><td>—</td><td>—</td><td>金丹化神、元婴出窍、化神领域、飞升羽化</td><td>4</td></tr></tbody></table><hr><h2 id="功法获取" tabindex="-1">功法获取 <a class="header-anchor" href="#功法获取" aria-label="Permalink to &quot;功法获取&quot;">​</a></h2><ul><li>达到功法要求的<strong>境界 + 小阶</strong>后自动解锁</li><li>无需额外学习或购买</li><li>使用指令 <code>/gongfa &lt;功法名&gt;</code> 释放（如 <code>/gongfa 万剑归宗</code>）</li></ul><hr><h2 id="推荐功法路线" tabindex="-1">推荐功法路线 <a class="header-anchor" href="#推荐功法路线" aria-label="Permalink to &quot;推荐功法路线&quot;">​</a></h2><h3 id="🔶-金灵根-极限输出" tabindex="-1">🔶 金灵根（极限输出） <a class="header-anchor" href="#🔶-金灵根-极限输出" aria-label="Permalink to &quot;🔶 金灵根（极限输出）&quot;">​</a></h3><p><code>灵刃斩 → 御剑术 → 金钟罩 → 天雷引 → 万剑归宗 → 大罗天斩</code></p><h3 id="🔥-火灵根-爆发aoe" tabindex="-1">🔥 火灵根（爆发AOE） <a class="header-anchor" href="#🔥-火灵根-爆发aoe" aria-label="Permalink to &quot;🔥 火灵根（爆发AOE）&quot;">​</a></h3><p><code>灵气弹 → 火蛇术 → 丹火焚天 → 焚天劫火 → 万雷归一</code></p><h3 id="🪨-土灵根-坦克生存" tabindex="-1">🪨 土灵根（坦克生存） <a class="header-anchor" href="#🪨-土灵根-坦克生存" aria-label="Permalink to &quot;🪨 土灵根（坦克生存）&quot;">​</a></h3><p><code>护体罡气 → 岩铠术 → 山岳镇压 → 不动明王 → 天劫护体</code></p><h3 id="🌿-木灵根-续航辅助" tabindex="-1">🌿 木灵根（续航辅助） <a class="header-anchor" href="#🌿-木灵根-续航辅助" aria-label="Permalink to &quot;🌿 木灵根（续航辅助）&quot;">​</a></h3><p><code>缠绕术 → 回春术 → 生生不息 → 万象森罗</code></p><h3 id="💧-水灵根-控制均衡" tabindex="-1">💧 水灵根（控制均衡） <a class="header-anchor" href="#💧-水灵根-控制均衡" aria-label="Permalink to &quot;💧 水灵根（控制均衡）&quot;">​</a></h3><p><code>水镜盾 → 缩地成寸 → 冰封术 → 沧海横流</code></p><h3 id="🌟-天灵根-万能全才" tabindex="-1">🌟 天灵根（万能全才） <a class="header-anchor" href="#🌟-天灵根-万能全才" aria-label="Permalink to &quot;🌟 天灵根（万能全才）&quot;">​</a></h3><p><code>金丹化神 → 元婴出窍 → 化神领域 → 飞升羽化</code> （天灵根功法 + 灵活搭配任意灵根攻防功法，享受 ×1.8 超强倍率）</p>',99)])])}const b=o(g,[["render",l]]);export{c as __pageData,b as default};
